mapper.select:
select sar.id, sar.main_agent_id as mainAgentId, main_ad.name as mainAgentName, sar.sub_agent_id as subAgentId, sub_ad.name as subAgentName, sar.update_time as updateTime, sar.status, sar.remark from sub_agent_relation sar inner join agent_definition main_ad on main_ad.id = sar.main_agent_id inner join agent_definition sub_ad on sub_ad.id = sar.sub_agent_id
and (main_ad.name like concat('%', #{pageRequest.keyword}, '%') or sub_ad.name like concat('%', #{pageRequest.keyword}, '%') or sar.remark like concat('%', #{pageRequest.keyword}, '%'))
and main_ad.name like concat('%', #{pageRequest.mainAgentName}, '%')
and sub_ad.name like concat('%', #{pageRequest.subAgentName}, '%')
and sar.status = #{pageRequest.status}
order by sar.update_time desc nulls last, sar.create_time desc nulls last limit #{size} offset #{offset}
